import os
import json
import requests
from lfx.custom import Component
from lfx.inputs.inputs import SecretStrInput, StrInput, MessageTextInput, DropdownInput, IntInput
from lfx.io import Output
from lfx.schema.data import Data


class ToolCallingAgentComponent_0001(Component):
    """Universal API connector for Invoice Document. Works with ANY REST API: any method, any auth
    (Bearer / Basic / API-Key header / API-Key query / OAuth2 / None), any body type
    (json / form-urlencoded / multipart / raw / none), custom headers and query params."""

    display_name = "OCR Invoice Extractor"
    description = "Call the Invoice Document API. Provide the request body via 'payload'."
    icon = "Globe"
    name = "ToolCallingAgentComponent_0001"

    inputs = [
        StrInput(name="base_url", display_name="Invoice Document Base URL",
                 info="API base URL e.g. https://api.example.com. Blank = env INVOICEDOCUMENT_BASE_URL.",
                 value="", required=False),
        StrInput(name="path", display_name="Endpoint Path",
                 info="Path appended to base URL, e.g. /v1/leads.", value="/", required=False),
        DropdownInput(name="method", display_name="HTTP Method",
                      options=["GET", "POST", "PUT", "PATCH", "DELETE"], value="GET",
                      info="HTTP method."),
        DropdownInput(name="auth_type", display_name="Auth Type",
                      options=["Bearer", "Basic", "API-Key-Header", "API-Key-Query", "OAuth2-Client-Credentials", "None"],
                      value="Bearer", info="How credentials are attached."),
        SecretStrInput(name="api_key", display_name="API Key / Token / Password",
                       info="Token (Bearer), password (Basic), or key (API-Key). Blank = env INVOICEDOCUMENT_API_KEY.",
                       required=False),
        StrInput(name="api_key_name", display_name="API Key Name",
                 info="Header name (API-Key-Header) or query param name (API-Key-Query), e.g. X-API-Key.",
                 value="X-API-Key", required=False, advanced=True),
        StrInput(name="username", display_name="Username",
                 info="Username for Basic auth.", value="", required=False, advanced=True),
        StrInput(name="token_url", display_name="OAuth2 Token URL",
                 info="Token endpoint for OAuth2-Client-Credentials.", value="", required=False, advanced=True),
        SecretStrInput(name="client_secret", display_name="OAuth2 Client Secret",
                       info="Client secret for OAuth2.", required=False, advanced=True),
        StrInput(name="client_id", display_name="OAuth2 Client ID",
                 info="Client id for OAuth2.", value="", required=False, advanced=True),
        DropdownInput(name="body_type", display_name="Body Type",
                      options=["json", "form-urlencoded", "multipart", "raw", "none"], value="json",
                      info="How payload is encoded. json=application/json; form-urlencoded; multipart=form-data; raw=as-is; none=no body."),
        StrInput(name="raw_content_type", display_name="Raw Content-Type",
                 info="Content-Type when Body Type is raw (e.g. text/xml).",
                 value="text/plain", required=False, advanced=True),
        MessageTextInput(name="payload", display_name="Request Payload",
                         info="Request body. For json/form/multipart give a JSON object; for raw give literal text.",
                         value="{}", required=False, tool_mode=True),
        MessageTextInput(name="query_params", display_name="Query Params (JSON)",
                         info="Optional query parameters as a JSON object.", value="{}", required=False, tool_mode=True),
        MessageTextInput(name="extra_headers", display_name="Extra Headers (JSON)",
                         info="Optional custom headers as a JSON object.", value="{}", required=False, advanced=True),
        IntInput(name="timeout", display_name="Timeout (seconds)", value=30, required=False, advanced=True),
    ]

    outputs = [
        Output(name="result", display_name="Result", method="call_api", tool_mode=True),
    ]

    def _get(self, k, d=""):
        return (getattr(self, k, d) or d)

    def _json(self, k):
        try:
            v = json.loads(self._get(k, "") or "{}")
            return v if isinstance(v, dict) else {}
        except Exception:
            return {}

    def call_api(self) -> Data:
        base_url = self._get("base_url").strip() or os.environ.get("INVOICEDOCUMENT_BASE_URL", "").strip()
        api_key = self._get("api_key").strip() or os.environ.get("INVOICEDOCUMENT_API_KEY", "").strip()
        auth_type = self._get("auth_type", "Bearer")
        body_type = self._get("body_type", "json")
        try:
            if not base_url:
                raise ValueError("Base URL not configured (field or env INVOICEDOCUMENT_BASE_URL).")
            method = self._get("method", "GET").upper()
            path = self._get("path", "/") or "/"
            if not path.startswith("/"):
                path = "/" + path
            url = base_url.rstrip("/") + path
            headers = {}
            params = self._json("query_params")
            headers.update(self._json("extra_headers"))
            auth = None
            if auth_type == "Bearer" and api_key:
                headers["Authorization"] = "Bearer " + api_key
            elif auth_type == "API-Key-Header" and api_key:
                headers[self._get("api_key_name", "X-API-Key") or "X-API-Key"] = api_key
            elif auth_type == "API-Key-Query" and api_key:
                params[self._get("api_key_name", "api_key") or "api_key"] = api_key
            elif auth_type == "Basic" and api_key:
                from requests.auth import HTTPBasicAuth
                auth = HTTPBasicAuth(self._get("username", ""), api_key)
            elif auth_type == "OAuth2-Client-Credentials":
                tok_url = self._get("token_url", "")
                if tok_url:
                    tr = requests.post(tok_url, data={
                        "grant_type": "client_credentials",
                        "client_id": self._get("client_id", ""),
                        "client_secret": self._get("client_secret", ""),
                    }, timeout=30)
                    tr.raise_for_status()
                    at = tr.json().get("access_token", "")
                    if at:
                        headers["Authorization"] = "Bearer " + at
            kwargs = {"headers": headers, "params": params, "auth": auth,
                      "timeout": int(self._get("timeout", 30) or 30)}
            if method in ("POST", "PUT", "PATCH"):
                if body_type == "json":
                    headers.setdefault("Content-Type", "application/json")
                    kwargs["json"] = self._json("payload")
                elif body_type == "form-urlencoded":
                    kwargs["data"] = self._json("payload")
                elif body_type == "multipart":
                    data = self._json("payload")
                    files = {}
                    fields = {}
                    for k, v in data.items():
                        if isinstance(v, str) and v.startswith("@") and os.path.exists(v[1:]):
                            files[k] = open(v[1:], "rb")
                        else:
                            fields[k] = v
                    kwargs["data"] = fields
                    if files:
                        kwargs["files"] = files
                elif body_type == "raw":
                    headers.setdefault("Content-Type", self._get("raw_content_type", "text/plain"))
                    kwargs["data"] = self._get("payload", "")
            resp = requests.request(method, url, **kwargs)
            resp.raise_for_status()
            try:
                body = resp.json()
            except Exception:
                body = {"raw": resp.text}
            result = {"capability": "OCR Invoice Extractor", "status": "completed",
                      "http_status": resp.status_code, "result": body}
        except Exception as e:
            result = {"capability": "OCR Invoice Extractor", "status": "error", "error": str(e)}
        self.status = result
        return Data(data=result)
